def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 3:
            priority += 5000 * np.tanh(usage_ratio - 2.5)
            if capacity > 7:
                priority += 150 * np.sqrt(capacity) + 20 * np.log(capacity + 1)
            else:
                priority -= 30 * np.exp(-usage_ratio)
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 2500 * delta**1.3 - 50 * np.sin(delta * np.pi * 3)
            for p in range(1, 7):
                priority += ((-1) ** p) * np.cos(usage_ratio * np.pi * p) * 12 / p
            if capacity % 2 < 0.5:
                priority -= 10 * np.sin(capacity * 5)
        elif 1 < usage_ratio <= 2:
            priority += 2000 * (1 - 1/usage_ratio)
            for q in range(1, 4):
                priority += np.log1p(q * capacity) * np.sin(q * usage_ratio * np.pi) * 5
            if capacity % 1.7 < 0.4:
                priority += 30 * np.cos(capacity * 4)
            if usage_ratio > 1.7:
                priority += 40
        elif 0.3 < usage_ratio <= 1:
            try:
                val = np.log(capacity + 0.1)
                priority += val * 15 / (usage_ratio + 0.1)
            except Exception:
                priority += 70
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.25:
                    priority += power * 18 / j
                    if j % 2 == 0:
                        priority += 3 * j
                else:
                    priority -= power * 12 / (j + 1)
                    if j == 7 and usage_ratio > 0.85:
                        priority += 9
            if capacity % 2.3 < 0.5:
                priority -= 25 * np.sin(capacity * 3)
        elif 0 <= usage_ratio <= 0.3:
            priority += 120 * (1 - usage_ratio)
            for x in range(1, 8):
                ratio_pow = usage_ratio ** x
                priority += (np.tan(ratio_pow * np.pi / 3) - 0.4) * 10 / x
                if usage_ratio < 0.05 * x:
                    priority -= 7 * x
            if capacity < 0.03:
                priority += np.sqrt(capacity)*300
            elif capacity < 0.4:
                priority += np.log1p(capacity * 20) * 30
            else:
                priority += (capacity % 2) * 20
        if capacity < 0.15:
            priority += 50
            if usage_ratio > 0.75:
                priority += 60
            elif usage_ratio < 0.12:
                priority -= 35
                for r in range(1, 6):
                    priority -= r * np.exp(-usage_ratio * 15)
        elif capacity < 1.2:
            priority += 30
            if usage_ratio > 0.9:
                priority += 55
            elif usage_ratio < 0.35:
                priority -= 20
        else:
            if usage_ratio < 0.25:
                priority -= 25
            elif usage_ratio > 0.97:
                priority += 70
            else:
                priority += 20
        proximity_score = 0
        if int(capacity * 2000) % 17 == 0:
            proximity_score += 15
        if int(capacity * 1000) % 19 == 0:
            proximity_score -= 10
        if int(capacity * 400) % 7 == 0:
            proximity_score += 12
        for k in range(1, 7):
            diff = abs(usage_ratio - k / 7)
            if diff < 0.025:
                proximity_score += 20 / k
            elif diff < 0.07:
                proximity_score += 10 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 6):
            mod_check = int(capacity * 1500) % (m + 7)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 2:
                proximity_score -= m * 3
        for n in range(1, 4):
            mod_check = int(usage_ratio * 1500) % (n + 4)
            if mod_check == 0:
                proximity_score += 8 * n
            elif mod_check == 2:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.015:
            for s in range(1, 6):
                priority -= s * 6
        elif usage_ratio > 0.985:
            for t in range(1, 6):
                priority += t * 7
        if capacity > 2:
            if capacity % 1 < 0.08:
                priority += 35
            if (int(capacity * 2000) % 23 == 0) and (usage_ratio > 0.6):
                priority += 50
        special_flag = False
        for prime in [3,5,7,11]:
            if int(capacity * 1000) % prime == 0:
                special_flag = not special_flag
        if special_flag:
            priority *= 1.05
            if usage_ratio < 0.4:
                priority += 20
            else:
                priority -= 15
        if abs(priority) > 15000:
            priority = np.sign(priority) * 15000
        priorities[i] = priority
    return priorities
